#!/usr/bin/env python
"""Writes trial_bindings.py (unified CLI, all modules) to MABE root."""
import base64, os, sys
if os.path.isfile("core/universal_schema.py"): root="."
elif os.path.isfile(os.path.join("..","core","universal_schema.py")): root=".."; os.chdir(root)
else: print("ERROR: Run from MABE root"); sys.exit(1)
content = base64.b64decode('').decode("utf-8")
with open("trial_bindings.py","w",encoding="utf-8") as f: f.write(content)
print(f"Wrote trial_bindings.py ({len(content)} bytes)")